<script lang="ts">let {data}=$props();</script><div class="hero"><div><h1>Data quality</h1><div class="muted">Actionable import, identity, matching, and source-coverage diagnostics.</div></div></div>{#if data.dataset}<div class="grid"><div class="card"><small>Roster imported</small><br/>{data.dataset.lastRosterImport??'Never'}</div><div class="card"><small>Sportlink imported</small><br/>{data.dataset.lastSportlinkImport??'Never'}</div><div class="card"><small>Twizzit imported</small><br/>{data.dataset.lastTwizzitImport??'Never'}</div></div>{/if}<div class="table-wrap"><table><thead><tr><th>Severity</th><th>Source</th><th>Issue</th><th>Reference</th><th>Detected</th></tr></thead><tbody>{#each data.rows as i}<tr><td><span class="pill" class:warn={i.severity==='warning'} class:error={i.severity==='error'}>{i.severity}</span></td><td>{i.source}</td><td><strong>{i.code.replaceAll('_',' ')}</strong><br/><span class="muted">{i.message}</span></td><td>{i.sourceRef??'—'}</td><td>{new Date(i.createdAt).toLocaleString('en-BE')}</td></tr>{/each}</tbody></table>{#if !data.rows.length}<div class="empty">{data.isAll?'Pick a specific team to view data-quality issues.':'No open data-quality issues.'}</div>{/if}</div>
